insert into public.issues (id, slug, title, summary, description, hot, published, views, participants, comments_count, reaction_count)
values
  ('10000000-0000-0000-0000-000000000001', 'presidential-term-reform', '대통령의 연임 개헌에 대한 나의 생각은?', '대통령 4년 연임제 도입과 권력구조 개편을 함께 논의해야 할까요?', '현행 5년 단임제와 4년 연임제, 분권형 개헌의 장단점을 비교합니다.', true, true, 0, 0, 0, 0),
  ('10000000-0000-0000-0000-000000000002', 'medical-school-quota', '의대 정원 확대, 어디까지 필요할까?', '지역 의료 공백 해소와 의료 교육의 질 사이에서 적정 확대 폭을 비교합니다.', '의대 정원 확대와 필수 의료 개선 정책의 선택지를 비교합니다.', true, true, 0, 0, 0, 0),
  ('10000000-0000-0000-0000-000000000003', 'youth-housing', '청년 주거 정책, 현금 지원 vs 공급 확대?', '월세 부담 완화와 도심 공급 확대의 우선순위를 묻습니다.', '청년 주거 불안 해소 정책을 비교합니다.', true, true, 0, 0, 0, 0),
  ('10000000-0000-0000-0000-000000000004', 'ai-regulation', 'AI 규제법, 혁신과 안전의 균형은?', '고위험 AI 규제, 투명성 의무, 산업 경쟁력 사이의 기준을 비교합니다.', 'AI 규제법의 강도와 적용 범위를 비교합니다.', false, true, 0, 0, 0, 0),
  ('10000000-0000-0000-0000-000000000005', 'regional-balance', '지역 균형 발전, 예산을 어디에 집중할까?', '수도권 집중 완화와 지역 성장 거점 전략의 우선순위를 비교합니다.', '지역 균형 발전 예산 배분 방향을 비교합니다.', false, true, 0, 0, 0, 0)
