insert into public.issue_options (id, issue_id, title, short_text, gradient, party_alignment, difference, pros, cons, sort_order)
values
  ('20000000-0000-0000-0000-000000000101', '10000000-0000-0000-0000-000000000001', '정책 연속성 강화 필요', '정책의 연속성이 높아지고 대통령이 국민 평가를 의식해 더 책임 있게 국정을 운영할 것이다.', 'linear-gradient(135deg,#244868,#345f8f,#e04b5d)', '국민개혁당 개헌특위와 가까운 입장', '연임제 찬성은 정책 성과에 대한 중간 평가를 제도화한다는 점에서 현행 유지와 다릅니다.', array['장기 국정과제의 추진력이 높아질 수 있어요.','성과가 낮은 정부를 선거로 교체할 명분도 명확해져요.'], array['현직 대통령 프리미엄이 커질 수 있어요.','선거 전략이 국정 운영을 좌우할 수 있어요.'], 1),
  ('20000000-0000-0000-0000-000000000102', '10000000-0000-0000-0000-000000000001', '권력 집중 위험', '대통령에게 권력이 지나치게 집중되어 장기 집권과 권력 남용 위험이 커질 것이다.', 'linear-gradient(135deg,#e4233f,#c83e54,#244868)', '민주미래당 견제론 그룹과 가까운 입장', '권력 집중 우려는 임기보다 견제 장치의 부재를 핵심 문제로 봅니다.', array['권력 남용 가능성을 먼저 점검합니다.','국회와 사법부 견제 장치를 함께 논의하게 합니다.'], array['정책 연속성 문제를 해결하지 못할 수 있어요.','모든 개헌 논의를 위험 프레임으로만 볼 수 있어요.'], 2),
  ('20000000-0000-0000-0000-000000000103', '10000000-0000-0000-0000-000000000001', '분권형 개헌 병행 필요', '대통령 권한 분산과 국회·지방정부의 견제 강화 같은 분권형 개헌과 함께 추진되어야 한다.', 'linear-gradient(135deg,#244868,#2b6f82,#d94b5e)', '지방분권 연대와 가까운 입장', '연임 여부보다 권한 배분 설계를 먼저 보자는 절충형 관점입니다.', array['찬반 양쪽의 우려를 제도 설계로 흡수할 수 있어요.','지방정부와 국회의 책임성을 함께 키울 수 있어요.'], array['논의 범위가 넓어져 합의 속도가 느릴 수 있어요.','세부 설계가 불명확하면 메시지가 흐려질 수 있어요.'], 3),
  ('20000000-0000-0000-0000-000000000104', '10000000-0000-0000-0000-000000000001', '현행 유지', '단임제의 장점을 유지하고 권력 견제와 정책 지속성은 법률과 국정 운영 방식으로 보완해야 한다.', 'linear-gradient(135deg,#4a5568,#2d3748,#23445f)', '제도 안정성을 강조하는 중도 그룹과 가까운 입장', '개헌보다 현재 제도 안에서 운영 방식을 개선하는 데 무게를 둡니다.', array['큰 제도 변경의 사회적 비용을 줄일 수 있어요.','권력 집중 우려를 구조적으로 피할 수 있어요.'], array['정책 단절 문제는 계속 남을 수 있어요.','현행 제도에 대한 시민 피로감을 해소하기 어려워요.'], 4),
  ('20000000-0000-0000-0000-000000000201', '10000000-0000-0000-0000-000000000002', '단계적 확대', '교육 인프라와 병행해 매년 점진적으로 늘려야 한다.', 'linear-gradient(135deg,#244868,#4472a6,#e15a6a)', '중도 보건의료 개혁안과 가까운 입장', '속도보다 지속 가능성을 중시합니다.', array['교육 질 저하를 줄여요.','의료계와 합의 여지가 커요.'], array['효과가 늦게 나타날 수 있어요.','지역 공백이 당장 해소되기 어려워요.'], 1),
  ('20000000-0000-0000-0000-000000000202', '10000000-0000-0000-0000-000000000002', '대규모 확대', '부족 규모를 감안해 빠르고 크게 늘려야 한다.', 'linear-gradient(135deg,#e4233f,#d45564,#244868)', '강한 공급 확대론과 가까운 입장', '의사 수 부족을 핵심 원인으로 봅니다.', array['지역과 필수의료 공급을 빠르게 늘릴 수 있어요.','경쟁 완화 효과를 기대할 수 있어요.'], array['수련 병원과 교수 확보가 부담이에요.','단기 갈등 비용이 커질 수 있어요.'], 2),
  ('20000000-0000-0000-0000-000000000203', '10000000-0000-0000-0000-000000000002', '지역의사제 병행', '정원 확대와 함께 지역 근무 의무와 지원책이 필요하다.', 'linear-gradient(135deg,#25636f,#2f7f8d,#e05263)', '지역균형 의료 그룹과 가까운 입장', '단순 증원보다 배치 구조를 함께 봅니다.', array['실제 지역 공백 해결에 직접적이에요.','장학금·주거 지원과 묶어 설계할 수 있어요.'], array['직업 선택 자유 논쟁이 생길 수 있어요.','의무 기간 종료 후 이탈 가능성이 있어요.'], 3),
  ('20000000-0000-0000-0000-000000000204', '10000000-0000-0000-0000-000000000002', '현행 유지', '정원보다 근무 환경과 수가 개선이 먼저다.', 'linear-gradient(135deg,#4a5568,#2d3748,#244868)', '의료체계 개선 우선론과 가까운 입장', '인력 총량보다 필수의료 유인을 우선합니다.', array['필수의료 현장의 원인을 정밀하게 봐요.','교육 질을 안정적으로 유지할 수 있어요.'], array['인력 부족 체감은 계속될 수 있어요.','증원 요구에 답이 부족해 보일 수 있어요.'], 4),
  ('20000000-0000-0000-0000-000000000301', '10000000-0000-0000-0000-000000000003', '월세 직접 지원', '당장 체감되는 주거비를 낮추기 위해 현금성 지원을 확대한다.', 'linear-gradient(135deg,#e4233f,#d05261,#244868)', '청년 생활비 지원론과 가까운 입장', '즉각적인 부담 완화에 초점을 둡니다.', array['정책 체감이 빠릅니다.','저소득 청년에게 직접 도움이 됩니다.'], array['임대료 상승으로 전가될 수 있습니다.','재정 지속성이 쟁점입니다.'], 1),
  ('20000000-0000-0000-0000-000000000302', '10000000-0000-0000-0000-000000000003', '도심 공급 확대', '교통 좋은 지역의 공공임대와 소형 주택 공급을 늘린다.', 'linear-gradient(135deg,#244868,#366999,#e75a68)', '도시 공급 확대론과 가까운 입장', '가격의 구조적 원인을 공급 부족으로 봅니다.', array['장기 가격 안정에 도움이 됩니다.','직주근접 문제를 함께 다룹니다.'], array['사업 기간이 길고 갈등이 큽니다.','입지 선정이 어려울 수 있습니다.'], 2),
  ('20000000-0000-0000-0000-000000000303', '10000000-0000-0000-0000-000000000003', '보증금 금융 지원', '저리 대출과 보증보험으로 초기 비용 장벽을 낮춘다.', 'linear-gradient(135deg,#255b76,#2c817a,#d95565)', '금융 접근성 개선론과 가까운 입장', '목돈 부족 문제를 해결하려는 접근입니다.', array['초기 진입 장벽을 낮춥니다.','예산 대비 지원 범위를 넓힐 수 있습니다.'], array['부채 부담이 남습니다.','소득이 낮으면 체감이 제한적입니다.'], 3),
  ('20000000-0000-0000-0000-000000000304', '10000000-0000-0000-0000-000000000003', '규제 완화', '민간 임대 공급을 늘리도록 세제와 용도 규제를 완화한다.', 'linear-gradient(135deg,#4a5568,#35516d,#244868)', '민간 공급 촉진론과 가까운 입장', '민간 참여를 통해 공급 속도를 높이자는 관점입니다.', array['민간 자본을 활용할 수 있습니다.','행정 부담이 줄 수 있습니다.'], array['공공성 확보가 어렵습니다.','취약계층 보호 장치가 필요합니다.'], 4),
  ('20000000-0000-0000-0000-000000000401', '10000000-0000-0000-0000-000000000004', '강한 사전 규제', '고위험 AI는 출시 전 안전성 심사를 의무화한다.', 'linear-gradient(135deg,#e4233f,#c64c5d,#244868)', '안전 우선 규제론과 가까운 입장', '피해 예방을 혁신 속도보다 우선합니다.', array['사회적 위험을 선제적으로 줄입니다.','책임 소재가 명확해집니다.'], array['스타트업 진입 장벽이 높아질 수 있습니다.','심사 기준이 느리면 혁신을 막을 수 있습니다.'], 1),
  ('20000000-0000-0000-0000-000000000402', '10000000-0000-0000-0000-000000000004', '위험 기반 규제', '위험 등급별로 의무를 달리하고 저위험 서비스는 완화한다.', 'linear-gradient(135deg,#244868,#346f91,#e15464)', '디지털 균형론과 가까운 입장', '모든 AI를 같은 강도로 보지 않는 절충안입니다.', array['안전과 혁신을 구분해 설계합니다.','현장 적용 가능성이 높습니다.'], array['위험 등급 판정이 논쟁적입니다.','감독 역량이 필요합니다.'], 2),
  ('20000000-0000-0000-0000-000000000403', '10000000-0000-0000-0000-000000000004', '투명성 의무 중심', 'AI 생성 표시, 학습 데이터 설명, 이의제기권을 우선 도입한다.', 'linear-gradient(135deg,#27516e,#2e7b7c,#db5364)', '이용자 권리 강화론과 가까운 입장', '통제보다 설명과 선택권을 중시합니다.', array['이용자의 판단권을 키웁니다.','기업 부담이 상대적으로 낮습니다.'], array['위험 자체를 막기엔 부족할 수 있습니다.','표시 의무가 형식화될 수 있습니다.'], 3),
  ('20000000-0000-0000-0000-000000000404', '10000000-0000-0000-0000-000000000004', '자율 규제', '산업 성장을 위해 민간 가이드라인과 사후 책임을 중심으로 한다.', 'linear-gradient(135deg,#4a5568,#314b65,#244868)', '산업 경쟁력 우선론과 가까운 입장', '빠른 기술 변화에 민간이 더 잘 대응한다는 관점입니다.', array['서비스 출시와 실험이 빨라집니다.','글로벌 경쟁에 유리할 수 있습니다.'], array['피해 발생 후 대응이 늦을 수 있습니다.','약한 기업은 기준을 지키기 어렵습니다.'], 4),
  ('20000000-0000-0000-0000-000000000501', '10000000-0000-0000-0000-000000000005', '공공기관 2차 이전', '중앙 공공기관과 연구기관을 추가 이전해 지역 일자리를 만든다.', 'linear-gradient(135deg,#244868,#386a98,#e65b69)', '분권 강화론과 가까운 입장', '공공 부문이 먼저 지역 수요를 만든다는 관점입니다.', array['지역 고용을 빠르게 만들 수 있습니다.','상징성이 큽니다.'], array['기관만 옮기면 가족·기업 이전은 제한적일 수 있습니다.','수도권 반발이 생길 수 있습니다.'], 1),
  ('20000000-0000-0000-0000-000000000502', '10000000-0000-0000-0000-000000000005', '광역 교통망 투자', '생활권을 넓히는 철도와 도로망에 우선 투자한다.', 'linear-gradient(135deg,#255674,#2f7f8d,#df5465)', '생활권 연결론과 가까운 입장', '이동 시간을 줄여 지역 선택지를 늘립니다.', array['출퇴근·통학 가능 범위를 넓힙니다.','기업 입지 매력을 높일 수 있습니다.'], array['대규모 예산과 긴 시간이 필요합니다.','수요 예측 실패 위험이 있습니다.'], 2),
  ('20000000-0000-0000-0000-000000000503', '10000000-0000-0000-0000-000000000005', '지역 대학 혁신', '지역 대학, 병원, 기업을 묶은 인재 생태계를 만든다.', 'linear-gradient(135deg,#e4233f,#c94d5f,#244868)', '교육·산업 클러스터론과 가까운 입장', '인재가 남을 이유를 만드는 데 초점을 둡니다.', array['청년 유출을 구조적으로 줄입니다.','산업 전환과 연결하기 좋습니다.'], array['성과가 느리게 나타납니다.','대학 간 격차가 커질 수 있습니다.'], 3),
  ('20000000-0000-0000-0000-000000000504', '10000000-0000-0000-0000-000000000005', '기업 세제 혜택', '지역 이전 기업에 세제·규제 특례를 강하게 제공한다.', 'linear-gradient(135deg,#4a5568,#31506a,#244868)', '민간 투자 유치론과 가까운 입장', '민간 일자리를 직접 끌어오려는 접근입니다.', array['기업 유치 효과가 빠를 수 있습니다.','지역 세수 기반을 만들 수 있습니다.'], array['혜택 종료 후 이탈 가능성이 있습니다.','지역 간 유치 경쟁이 과열될 수 있습니다.'], 4)
